      "keystrokes": "python3 - <<'PY'\nimport json, statistics, collections\nfor fn in ['requests_bucket_1.jsonl','requests_bucket_2.jsonl']:\n    reqs=[json.loads(l) for l in open('/app/task_file/input_data/'+fn)]\n    ps=[r['prompt_len'] for r in reqs]; gs=[r['gen_len'] for r in reqs]\n    print(fn, 'n=', len(reqs))\n    print(' prompt min/max/median/mean:', min(ps), max(ps), statistics.median(ps), round(sum(ps)/len(ps),2))\n    print(' gen min/max/median/mean:', min(gs), max(gs), statistics.median(gs), round(sum(gs)/len(gs),2))\n    sac=collections.Counter(((p+63)//64)*64 for p in ps)\n    print(' seq_align buckets:', dict(sorted(sac.items())))\n    print(' total raw prompt tokens:', sum(ps), 'total aligned prompt tokens:', sum(sac.elements()))\n    print()\nPY\n",
